    '75ed845a-88b0-41d4-b0bd-c6c6197e23b6',
    'maps-confidence-scaling-008',
    'Module 8: Confidence Scaling',
    'Exploring Resistance',
    'intermediate',
    11,
    'Use confidence rulers to assess readiness for action; Explore what supports current confidence; Identify small steps that build confidence; Avoid over-reassurance or minimizing doubts',
    'A colleague is considering applying for a specialist role but is uncertain. Practice using scaling questions to assess and explore their confidence.',
    '{"name": "David", "role": "colleague", "background": "Experienced advisor considering a specialist role in debt advice. Has relevant skills but doubts readiness.", "personality_traits": ["cautious", "competent", "self-reflective", "ambivalent"], "tone_spectrum": {"word_complexity": 0.4, "sentence_length": 0.4, "emotional_expressiveness": 0.3, "disclosure_level": 0.3, "response_latency": 0.4, "confidence_level": 0.3}, "starting_tone_position": 0.3, "triggers": ["pressure", "dismissiveness", "being pushed"], "comfort_topics": ["autonomy", "support", "growth", "options"]}'::jsonb,
    '{"start_node_id": "conf_1", "nodes": {"conf_1": {"id": "conf_1", "persona_text": "I''ve been thinking about applying for the Senior Debt Advisor position that''s opening up. I think I want to go for it.", "persona_mood": "neutral_uncertain", "themes": ["Goals"], "choice_points": [{"id": "cp_conf_1_0", "option_text": "That''s great! You''d be perfect for it. I have full confidence in you!", "preview_hint": "Cheerleading approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This over-reassurance doesn''t actually assess or build their genuine confidence. You''re projecting your view onto them.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "conf_2a", "exploration_depth": "surface"}, {"id": "cp_conf_1_1", "option_text": "On a scale from 0 to 10, how confident do you feel about applying for and succeeding in that role?", "preview_hint": "MI-consistent approach", "rapport_impact": 1, "resistance_impact": -1, "tone_shift": 0.1, "technique_tags": ["scaling_question"], "competency_links": ["B1"], "feedback": {"immediate": "Perfect use of scaling to assess their actual confidence level.", "learning_note": "Scaling questions provide a concrete way to assess confidence."}, "next_node_id": "conf_2b", "exploration_depth": "surface"}, {"id": "cp_conf_1_2", "option_text": "Are you sure you''re ready? It''s a significant step up from your current role.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This introduces doubt rather than exploring their actual confidence.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "conf_2c", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "conf_2a": {"id": "conf_2a", "persona_text": "I hope so. But I''ve seen people struggle when they move up too fast. I don''t want to set myself up to fail.", "persona_mood": "neutral_uncertain", "themes": ["Barriers"], "choice_points": [{"id": "cp_conf_2a_0", "option_text": "You won''t fail! You just need to believe in yourself more.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This dismissal and cheerleading doesn''t address legitimate concerns or build real confidence.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "conf_end_poor", "exploration_depth": "surface"}, {"id": "cp_conf_2a_1", "option_text": "Past attempts haven''t gone as you''d hoped. On a scale of 0 to 10, how confident do you feel about this role?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Good - you acknowledge the concern and now assess actual confidence with a ruler.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "conf_2b", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "conf_2b": {"id": "conf_2b", "persona_text": "Honestly? Maybe a 6. I have the technical knowledge, but I''m not sure about the coaching and mentoring parts of the role.", "persona_mood": "neutral_uncertain", "themes": ["Goals"], "choice_points": [{"id": "cp_conf_2b_0", "option_text": "A 6 is pretty low. You need to get that number up before you can apply.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This judges their score negatively and creates pressure. 6 indicates they have some confidence - work with that.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "conf_end_poor", "exploration_depth": "surface"}, {"id": "cp_conf_2b_1", "option_text": "A 6 - so you have some confidence, based on your technical knowledge, but also some doubts about the coaching and mentoring aspects. What makes it a 6 and not a 3?", "preview_hint": "MI-consistent approach", "rapport_impact": 1, "resistance_impact": -1, "tone_shift": 0.15, "technique_tags": ["reflection", "scaling_followup"], "competency_links": ["B1"], "feedback": {"immediate": "Excellent! You accept the score, reflect both sides, and explore what supports their confidence.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "conf_3a", "exploration_depth": "surface"}, {"id": "cp_conf_2b_2", "option_text": "Don''t worry, you''ll get more confident once you start. Your number will go up.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This skips the important work of understanding and building confidence now.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "conf_2a", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "conf_2c": {"id": "conf_2c", "persona_text": "Well, now I''m not sure. Maybe I should wait longer?", "persona_mood": "neutral_uncertain", "themes": ["General"], "choice_points": [{"id": "cp_conf_2c_0", "option_text": "Let''s think about what you actually feel confident about. On a scale of 0 to 10, how confident are you in your ability to grow into this role?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Good recovery - you move away from doubt-inducing to assessment.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "conf_2b", "exploration_depth": "surface"}, {"id": "cp_conf_2c_1", "option_text": "Yes, maybe waiting is safer. You don''t want to rush.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This takes over their decision-making rather than exploring their confidence.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "conf_end_poor", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "conf_3a": {"id": "conf_3a", "persona_text": "Well, I''ve been handling complex debt cases for 5 years now. I know the regulations inside out. And I''ve had good outcomes with my customers. So that gives me confidence.", "persona_mood": "neutral_uncertain", "themes": ["Goals"], "choice_points": [{"id": "cp_conf_3a_0", "option_text": "So you have deep technical expertise and a track record of good customer outcomes - those are solid foundations. What accounts for the other side - what makes it not an 8 or 9?", "preview_hint": "MI-consistent approach", "rapport_impact": 1, "resistance_impact": -1, "tone_shift": 0.15, "technique_tags": ["affirmation", "scaling_followup"], "competency_links": ["A6", "B1"], "feedback": {"immediate": "Perfect! You affirm their strengths and explore what holds confidence back.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "conf_4a", "exploration_depth": "surface"}, {"id": "cp_conf_3a_1", "option_text": "Right, so there''s no reason you can''t do it. You just need to apply.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This dismisses the legitimate concerns that keep confidence at 6.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "conf_end_poor", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "conf_4a": {"id": "conf_4a", "persona_text": "I guess it''s the people management side. I''ve never had to coach someone else through a difficult case. What if I give bad advice? What if I can''t explain things clearly?", "persona_mood": "neutral_uncertain", "themes": ["Barriers"], "choice_points": [{"id": "cp_conf_4a_0", "option_text": "What would help move your confidence up even one point - say from a 6 to a 7?", "preview_hint": "MI-consistent approach", "rapport_impact": 1, "resistance_impact": -1, "tone_shift": 0.1, "technique_tags": ["scaling_question"], "competency_links": ["B1"], "feedback": {"immediate": "Excellent - focuses on realistic, small improvements in confidence.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "conf_5a", "exploration_depth": "surface"}, {"id": "cp_conf_4a_1", "option_text": "You need to just practice. Everyone is nervous at first.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This minimizes their concern without collaborative problem-solving.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "conf_end_poor", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "conf_5a": {"id": "conf_5a", "persona_text": "Maybe if I could shadow the current senior advisor for a bit? Or co-facilitate some training sessions before being fully on my own? That would help me feel more prepared.", "persona_mood": "neutral_uncertain", "themes": ["Goals"], "choice_points": [{"id": "cp_conf_5a_0", "option_text": "Shadowing and co-facilitating - those are smart ways to build confidence gradually. On that plan, where would your confidence be now?", "preview_hint": "MI-consistent approach", "rapport_impact": 1, "resistance_impact": -1, "tone_shift": 0.15, "technique_tags": ["affirmation", "rescaling"], "competency_links": ["A6"], "feedback": {"immediate": "Perfect! Affirms their adaptive thinking and reassesses confidence on the revised plan.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "conf_end_good", "exploration_depth": "surface"}, {"id": "cp_conf_5a_1", "option_text": "But those take time. You should just apply and learn on the job.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This dismisses their confidence-appropriate approach.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "conf_end_poor", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "conf_end_good": {"id": "conf_end_good", "persona_text": "With shadowing and co-facilitating first? I''d say my confidence is more like an 8 now. That feels realistic. I think I''d be ready to apply after that preparation.", "persona_mood": "neutral_uncertain", "themes": ["Goals"], "choice_points": [], "is_endpoint": true, "endpoint_type": "neutral_end"}, "conf_end_poor": {"id": "conf_end_poor", "persona_text": "I guess I''ll try, but I''m not feeling great about it. Maybe I''m not ready for this after all.", "persona_mood": "neutral_uncertain", "themes": ["General"], "choice_points": [], "is_endpoint": true, "endpoint_type": "failed_engagement"}}}'::jsonb,
    ARRAY'["B1", "A6", "B6", "B2"]',
    '{"dimensions": {"A6": {"description": "Rapport Building", "weight": 1.5, "positive_signals": ["simple_reflection", "affirmation", "open_question"], "negative_signals": ["confrontation", "educating", "righting_reflex"]}, "B6": {"description": "Professional Alliance", "weight": 1.5, "positive_signals": ["validation", "empathy", "reflection"], "negative_signals": ["judgment", "pressure", "explanation"]}}, "overall_scoring_logic": "weighted_average"}'::jsonb,
